// Longitud máxima aproximada por párrafo
const maxChars = 400;

/**
 * Normaliza listas para que:
 * - Cada ítem vaya en una línea separada
 * - Haya una línea en blanco entre ítems
 * - Siempre sean listas numeradas en Markdown: "1. ...", "2. ..."
 */
function normalizarListasMarkdown(texto) {
  if (!texto) return '';

  const lineasOriginales = String(texto).split('\n');

  const nuevasLineas = [];
  const esLineaLista = [];

  let enLista = false;
  let contador = 0;

  for (let i = 0; i < lineasOriginales.length; i++) {
    let linea = lineasOriginales[i].trimEnd(); // mantenemos posibles espacios iniciales

    // Detectamos bullets típicos:
    // - "- algo", "* algo", "• algo"
    // - "1. algo", "1) algo"
    const match = linea.match(/^\s*(?:([-*•])\s+|(\d+)[\.\)]\s+)(.+)$/);

    if (match) {
      const contenido = (match[3] || '').trim();
      if (!contenido) {
        continue;
      }

      if (!enLista) {
        enLista = true;
        contador = 1;
      } else {
        contador++;
      }

      // Siempre numeramos en formato Markdown: "n. contenido"
      linea = `${contador}. ${contenido}`;
      nuevasLineas.push(linea.trim());
      esLineaLista.push(true);
    } else {
      // Línea normal (no de lista)
      enLista = false;
      contador = 0;

      // Respetamos líneas en blanco
      if (linea === '') {
        nuevasLineas.push('');
        esLineaLista.push(false);
      } else {
        nuevasLineas.push(linea);
        esLineaLista.push(false);
      }
    }
  }

  // Recomponemos el texto asegurando línea en blanco entre ítems de lista
  let resultado = '';

  for (let i = 0; i < nuevasLineas.length; i++) {
    const linea = nuevasLineas[i];

    if (i > 0) {
      if (esLineaLista[i] && esLineaLista[i - 1]) {
        // Entre dos ítems de lista => doble salto de línea
        resultado += '\n\n';
      } else {
        // Resto de casos => salto normal
        resultado += '\n';
      }
    }

    resultado += linea;
  }

  // Limpiamos exceso de líneas en blanco (máximo doble salto)
  resultado = resultado.replace(/\n{3,}/g, '\n\n');

  return resultado.trim();
}

function formatearTexto(textoBruto) {
  // Normalizamos saltos de línea
  let texto = String(textoBruto || '').replace(/\r\n/g, '\n').trim();

  if (!texto) return '';

  // Forzamos que las listas/enumeraciones empiecen en línea nueva
  // Ejemplos detectados:
  // "1. algo", "2) algo", "- algo", "* algo", "• algo"
  texto = texto
    .replace(/\s*((?:\d+[\.\)]\s+|[-*•]\s+))/g, '\n\n$1')
    .trim();

  // ¿El texto ya tiene párrafos (doble salto de línea)?
  if (texto.includes('\n\n')) {
    // Solo normalizamos listas y salimos, respetando el resto
    return normalizarListasMarkdown(texto);
  }

  // Si no hay párrafos, creamos párrafos a partir de frases y longitud máxima
  const frases = texto.match(/[^.!?]+[.!?]?/g) || [texto];

  const parrafos = [];
  let actual = '';

  for (const frase of frases) {
    const f = frase.trim();
    if (!f) continue;

    const candidata = actual ? actual + ' ' + f : f;

    if (candidata.length > maxChars && actual) {
      parrafos.push(actual.trim());
      actual = f;
    } else {
      actual = candidata;
    }
  }

  if (actual.trim()) {
    parrafos.push(actual.trim());
  }

  const textoConParrafos = parrafos.join('\n\n');

  // Siempre terminamos normalizando listas en el texto final
  return normalizarListasMarkdown(textoConParrafos);
}

