const items = $input.all();
const resultados = [];

for (const item of items) {
  const data = item.json || {};

  // De dónde sacamos la respuesta del agente
  let texto = data.respuesta_bot ?? data.output ?? data.text ?? '';

  // Si viene en objeto (p.ej. { text: "..." })
  if (texto && typeof texto === 'object') {
    if (typeof texto.text === 'string') {
      texto = texto.text;
    } else if (Array.isArray(texto)) {
      texto = texto.join(' ');
    } else {
      texto = JSON.stringify(texto);
    }
  }

  // Si no hay texto, devolvemos el item tal cual
  if (typeof texto !== 'string' || !texto.trim()) {
    resultados.push(item);
    continue;
  }

  // Formateamos el texto a párrafos + listas premium
  const textoFormateado = formatearTexto(texto);

  // Sobrescribimos SOLO el campo output
  resultados.push({
    json: {
      ...data,
      output: textoFormateado,
    },
  });
}

return resultados;

// Obtenemos el item de entrada
const item = $input.first();
const texto = (item.json.output ?? "").toString().trim();

// Si no hay texto, devolvemos 0 palabras
if (!texto) {
	return [
		{
			json: {
				numeroDePalabras: 0
			}
		}
	];
}

// Reemplazamos saltos de línea múltiples para evitar falsos vacíos
const normalizado = texto.replace(/\s+/g, " ").trim();

// Dividimos por espacios
const palabras = normalizado.length > 0 ? normalizado.split(" ") : [];

// Total de palabras
const cantidad = palabras.length;

// Devolvemos el resultado
return [
	{
		json: {
			numeroDePalabras: cantidad
		}
	}
];
